<?php
$page='teachers_rfid';
require_once __DIR__.'/../../config/perpus.php';
sds_perpus_ensure_schema($conn);
if(empty($_SESSION['csrf_teacher_rfid']))$_SESSION['csrf_teacher_rfid']=bin2hex(random_bytes(24));
$q=trim((string)($_GET['q']??''));$card=trim((string)($_GET['kartu']??''));$status=trim((string)($_GET['status']??''));if(!in_array($card,['terpasang','kosong'],true))$card='';if(!in_array($status,['aktif','nonaktif'],true))$status='';
$where=['1=1'];$params=[];$types='';if($q!==''){$where[]='(p.nama_lengkap LIKE ? OR p.nip LIKE ? OR p.jabatan LIKE ? OR kr.uid LIKE ?)';$like='%'.$q.'%';array_push($params,$like,$like,$like,$like);$types.='ssss';}if($card==='terpasang')$where[]='kr.id IS NOT NULL';elseif($card==='kosong')$where[]='kr.id IS NULL';if($status==='aktif')$where[]="p.active='Y'";elseif($status==='nonaktif')$where[]="p.active='N'";
$sql="SELECT p.pegawai_id,p.nip,p.nama_lengkap,p.jabatan,p.avatar,p.active,kr.uid,kr.tanggal_terbit FROM pegawai p LEFT JOIN kartu_rfid kr ON kr.pemilik_tipe='pegawai' AND kr.pemilik_id=p.pegawai_id WHERE ".implode(' AND ',$where).' ORDER BY CASE WHEN kr.id IS NULL THEN 0 ELSE 1 END,p.nama_lengkap';$stmt=$conn->prepare($sql);if($types){$refs=[$types];foreach($params as $i=>&$v)$refs[]=&$v;call_user_func_array([$stmt,'bind_param'],$refs);}$stmt->execute();$rows=$stmt->get_result()->fetch_all(MYSQLI_ASSOC);$stmt->close();
$stats=['total'=>0,'assigned'=>0,'empty'=>0,'active'=>0];$r=$conn->query("SELECT COUNT(*) total,SUM(kr.id IS NOT NULL) assigned,SUM(kr.id IS NULL) empty,SUM(p.active='Y') active FROM pegawai p LEFT JOIN kartu_rfid kr ON kr.pemilik_tipe='pegawai' AND kr.pemilik_id=p.pegawai_id");if($r){$x=$r->fetch_assoc();$stats=['total'=>(int)$x['total'],'assigned'=>(int)$x['assigned'],'empty'=>(int)$x['empty'],'active'=>(int)$x['active']];}
require __DIR__.'/partials/shared/master_page_style.php';
?>
